typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

__kernel void dummy_kernel()
{
}

__kernel void pgain_kernel(__global const Point_Struct *p,
                           __global const float *coord,
                           __global float *work_mem,
                           __global const int *center_table,
                           __global char *switch_membership,
                           __local float *x_coord,
                           const int num,
                           const int dim,
                           const long x,
                           const int K)
{
    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);
    const int gid = (int)get_global_id(0);

    for (int d = lid; d < dim; d += lsize) {
        x_coord[d] = coord[d * num + (int)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= num) return;

    Point_Struct pt = p[gid];

    float dist = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + gid] - x_coord[d];
        dist += diff * diff;
    }

    float x_cost = dist * pt.weight;
    float current_cost = pt.cost;
    int base = gid * (K + 1);

    if (x_cost < current_cost) {
        switch_membership[gid] = '1';
        work_mem[base + K] = x_cost - current_cost;
    } else {
        int assign = (int)pt.assign;
        int cidx = center_table[assign];
        work_mem[base + cidx] = current_cost - x_cost;
    }
}
